---@class LBattleLogicMgr
local LBattleLogicMgr = classX("LBattleLogicMgr", nil)

function LBattleLogicMgr:ctor(reportId, reportData)
    ---@type string
    self._reportId = reportId
    ---@type LFightReportData
    self._reportData = reportData								--战斗数据

    ---@type LBattleAgent
    self._agent = nil

    ---数据集管理器，外部设置，不要自行释放
    ---@type LBattleDataMgr
    self._dataMgr = nil
    
    ---@type LBattleLogicUnitMgr
    self._unitMgr = nil

    ---@type LBattleLogicLogMgr
    self._logMgr = nil

    ---@type LBattleFsm
    self._fsm = nil



    self._roundCount					= 0  --当前回合 从回合0 开始
    self._curRoundIndex                   	= 0                 --当前回合下标
    self._curBoutIndex						= 0					--当前出手
    self._curActionIndex						= 0					--当前Action
    self._totalRoundIndex					= 0					-- 战斗回合数量下表
    self._curTotalBout						= 0 				--本次回合总出手
    self._curTotalAction					= 0 				--本次出手总表演次数

    ---@type LFightRoundData
    self._curRoundData 					= nil 			--当前回合数据
    ---@type LFightBoutData
    self._curBoutData					= nil			--当前出手数据

    self._battleType					= 0						--战斗类型
    self._battleConfig               = nil                   --战斗额外数据，根据战斗类型变化

    self._isPlayingSilently              = false                 --是否后台战斗
    self._isBackToBattle                = false                 --是否回到战斗场景中

    self._rewardTable					= nil					--回放战斗的结算数据
    self._isPlayback					= nil					--是否回放

    self._isBattleEnd                   = false                 --这场战斗是否结束，结束就不用重返战场了
    self._skipBattle                    = false                 --跳过战斗

    self._offlineTime					= 0					-- 离线时间
    self._offlineRound					= 0					-- 离线回合

    self._isViewActFinished                   = false             -- 表演结束

    self._teamHurtCnt = {}

    self._time = 0
end

function LBattleLogicMgr:Initialize()
    if self._isInit then
        return
    end

    if not self._reportData or not self._reportData.isReportInit then
        return
    end

    self:InitAgent()

    self._logMgr = require("LApp.gameplay.videobattle.logic.LBattleLogicLogMgr"):new(self)

    self._unitMgr = require("LApp.gameplay.videobattle.logic.LBattleLogicUnitMgr"):new(self)
    self._unitMgr:Initialize()
    self._unitMgr:LoadFromReport(self._reportData)

    self._fsm = require("LApp.gameplay.videobattle.fsm.LBattleFsm"):new()
    self._fsm:SetVar("BattleLogicMgr", self)
    self._fsm:Initialize()
    self._fsm:SetUpdateFrequency(0)
    self._fsm:SetEnable(true)

    self._isBattleEnd = false
    self._isInit = true
    self._isStart = false
end

function LBattleLogicMgr:IsLive()
    return self._isStart
end

function LBattleLogicMgr:PlayBattle()
    if not self._isInit or self._fsm:IsCurState(BattleFsmState.Play) then
        return
    end
    self._isBattleEnd = false
    self._isEndFinished = false

    self._isToFront = false

    self._reportData:SetState(BattleState.Battle)
    self._fsm:ChangeState(BattleFsmState.Play)

    if not self._isStart then
        self._time = 0
        self._isStart = true
        self._agent:S2C_OnBattleStart(self._reportData)
    end
    self._isViewActFinished = true
    self:StepNextAction(false)
    self:StepNext(true)
end

function LBattleLogicMgr:StepNext(bNext)
    if self._fsm then
        self._fsm:SetVar("NextReady", bNext)
    end
end

function LBattleLogicMgr:SetDataMgr(dataMgr)
    self._dataMgr = dataMgr
end

function LBattleLogicMgr:InitAgent()
    self._agent = require("LApp.gameplay.videobattle.agent.LBattleAgent"):new()
    self._agent:Initialize()
    self._agent:SetLogicMgr(self)
end

function LBattleLogicMgr:GetAgent()
    return self._agent
end

function LBattleLogicMgr:SetBattleConfig(config)
    self._battleConfig = config

    if config and config.battleType then
        self._battleType = config.battleType
    end
end

function LBattleLogicMgr:GetBattleConfig()
    return self._battleConfig
end

function LBattleLogicMgr:InitCombatExtraData(extraData)
    if not extraData then
        return
    end

    self._battleConfig = extraData
    self.battleEndfun = extraData.battleEndfun

    --self._isPlayback = extraData.isPlayback
    self._rewardTable = extraData.rewardTable
    self._offlineTime = extraData.offlineTime or 0
end

function LBattleLogicMgr:InitBattleReport(reportTable)
    --初始化战报数据
    local battleReportData = require("LApp.gameplay.videobattle.data.LFightReportData"):new()
    battleReportData:InitData(reportTable)
    self._reportData = battleReportData
    self._totalRoundIndex = battleReportData:GetTotalRound()
end


function LBattleLogicMgr:InitBattle()
    self._bBattleInit = true

    self:InitFormationData()

    self:CalcOfflineRoundCount()

    self:StartRun()

end

---@region 战斗流程控制

---切回前台
function LBattleLogicMgr:C2S_SetViewActFinish(isOK)
    self._isViewActFinished = isOK
end

function LBattleLogicMgr:C2S_ExecuteNext()
    if self._isViewActFinished and self._waitTime <= self:GetTime() then
        self._fsm:GetCurState():Execute()
    end
end

function LBattleLogicMgr:IsBackgroundPlay()
    return self._isPlayingSilently
end

function LBattleLogicMgr:SetProtectOnToFront()
    self._isToFront = true
    self._fsm:ChangeState(BattleFsmState.Idle)
end

function LBattleLogicMgr:OnUpdate(time, deltaTime)
    if self._isToFront then
        return
    end

    if self._isEndFinished then
        return
    end

    if self._isBattleEnd then
        self._isBattleEndTime = self._isBattleEndTime - deltaTime
        if self._isBattleEndTime <= 0 then
            self._isBattleEnd = true
            self._isEndFinished = true
            FireEvent(EventNames.BATTLE_SHOW_END, self._reportData, self._battleConfig)
            return
        end
    end

    self._time = self._time + deltaTime
    time = self._time

    if self._unitMgr then
        self._unitMgr:OnUpdate(time,deltaTime)
    end

    if self._isViewActFinished and self._stepNextAction and self._waitTime <= time then
        self:StepNextAction(false)
        self:StepNext(true)
    end

    if self._fsm then
        if self._fsm:IsCurState(BattleFsmState.Pause)  then
            return
        end
        self._fsm:OnUpdate(time, deltaTime)
    end
end

---设置标记可以自动的一直在后台播放
function LBattleLogicMgr:SetAutoNext(bAutoNext, bRunStep)
    if self._isEndFinished then
        ---战斗已经结束了 不退回了
        return
    end
    self._isViewActFinished = bAutoNext
    self._isPlayingSilently = bRunStep
    if not bRunStep then
        self:StepNext(false)
    else
        ---后台战斗 清理标记
        self:PlayBattle()
    end
end

function LBattleLogicMgr:RequestNext()
    --TODO
    --边打边请求战报的战斗
end

function LBattleLogicMgr:OnLogicBattleEnd()
    if self._reportData then
        self._reportData:SetState(BattleState.Finished)
    end
    if self._fsm then
        self._fsm:ChangeState(BattleFsmState.Idle)
    end
    self._isBattleEnd = true
    self._isEndFinished = false
    self._isBattleEndTime = 2
    self._isStart = false
end

function LBattleLogicMgr:SkipBattle()
    if self._reportData then
        self._reportData:SetState(BattleState.Finished)
    end
    if self._fsm then
        self._fsm:ChangeState(BattleFsmState.Idle)
    end
    self._isBattleEnd = true
    self._isEndFinished = true
    self._isStart = false
    FireEvent(EventNames.BATTLE_SHOW_END, self._reportData, self._battleConfig)
end

---@param roundData LFightRoundData
function LBattleLogicMgr:PlayRound(roundIndex, roundData)
    self._playedHeros = {}

    self._curRoundData = roundData
    self._roundCount = roundData and roundData.round or 0
    self._curRoundIndex = roundIndex

    local round = self._roundCount < 1 and 1 or self._roundCount

    self:OnRoundUpdate(round)

    if self:IsOfflineRound() then
        return
    end

    if self._agent then
        self._agent:S2C_OnPlayRound()
    end
end

function LBattleLogicMgr:PlayBout(roundIdx, boutIdx, boutData)
    self._curBoutIdx = boutIdx
    self._curBoutData = boutData
end

---@param bout LFightBoutData
---@param boutActionListData LBattleBoutActionListData
function LBattleLogicMgr:PlayActionList(bout, actionIndex, boutActionListData)
    self._curActionIndex = actionIndex

    self._unitMgr:CheckRemoveSummon()

    local atkId = bout.aId or ''
    local skillId = bout.skill or 0

    local recordPlayHeroId = nil

    if skillId > 0 then
        self._playedHeros[atkId] = true
        recordPlayHeroId = atkId
    end

    local skillTime = 1
    local skillPlayTime = 1
    local time = self:GetTime()
    local skillDataList = {}

    local atkSide = nil
    local hasChangeSpineState = false
    local updateTreasureCdCount = 0
    local updateBuffCount = 0

    local logMgr = self._logMgr
    local dataMgr = self._dataMgr
    local IsLog = logMgr:IsLogOpen()

    local actionDataList =  boutActionListData.list
    if #actionDataList == 0 then
        skillTime = 0
    end
    for k,actionData in ipairs(actionDataList) do
        local aId = 0
        local skillRefId = 0
        local expressionRefId = 0
        --if totalAction == 0 then --没有acion数据 ，用bout里面的攻击目标和技能
        --    aId = boutData:GetAttackId()
        --    skillRefId = boutData:GetSkill()
            --expressionRefId = boutData:GetExpress()
        --else
            aId = actionData.aId
            skillRefId = actionData.skill
            expressionRefId = actionData.express
        --end

        local heroData = self:GetLogicUnit(aId)

        ---刷新神器回合显示
        --local atkObj = self._objCtrl:GetUnitView(aId)
        --if atkObj then
        --	local objType = atkObj:GetObjectType()
        --	if objType == LFightConst.OBJ_ARTIFACT then
        --		local isLeft = atkObj:GetTeamIdx() == BattleTeamSide.teamA
        --		self:GenArtifactCd(isLeft)
        --	end
        --end

        ---刷新宝物技能显示
        if heroData then
            local objType = heroData:GetBattleObjType()
            if objType == LFightConst.OBJ_TREASURE then
                if heroData:GenTreasureCd(skillRefId) then
                    updateTreasureCdCount = updateTreasureCdCount + 1
                end
            end
        end
        ---更新数据模型
        self:UpdateHeroDataFromActionData(actionData)
        --Ninfo("UpdateHeroDataFromActionData ")
        local hurtCount = self:GetHurtCountFromActionData(actionData)
        --print("攻击次数：" .. hurtCount)
        if self:UpdateHeroDataBuffData() then
            updateBuffCount = updateBuffCount + 1
        end

        local isIns = false
        local skillData
        local isChangeSpine = heroData and heroData.isChangeSpine and not heroData.isDead
        local isCreateSkillData = false
        if isChangeSpine then
            --- 变身下，直接从皮肤拿表现
            local expressionId = dataMgr:GetSkinExpress(heroData:GetSkinId(),expressionRefId,true)
            if expressionId and expressionId > 0 then
                isCreateSkillData = true
                skillData = heroData:GetSkillTransformData(skillRefId,expressionId,expressionRefId) or nil
                if skillData then
                    local _skillTime,_skillTimeInclu = skillData:GetSkillShowTime()
                    _skillTime = _skillTime or 0
                    _skillTimeInclu = _skillTimeInclu or 0
                    skillTime =  math.max(_skillTime, skillTime)
                    isIns = true
                    table.insert(skillDataList,{skillData = skillData,time = time,skillTime = skillTime,actionData = actionData,aId = aId})
                end
            end
            hasChangeSpineState = true
        end

        skillData = heroData and heroData:GetSkillData(skillRefId,expressionRefId,hurtCount) or nil

        if skillData then
            local _skillTime,_skillTimeInclu = skillData:GetSkillShowTime()
            _skillTime = _skillTime or 0
            _skillTimeInclu = _skillTimeInclu or 0

            skillTime =  math.max(_skillTime, skillTime)
            skillPlayTime = math.max(_skillTimeInclu, skillPlayTime)

            atkSide = heroData:GetTeamType()
        else
            if not isIns then
                skillTime = 0
                skillPlayTime = Time.deltaTime
            end
        end

        if IsLog then
            logMgr:LogNormal(string.format("skilltime %s ,skillTimeBack %s",tostring(skillTime),tostring(skillPlayTime)))
        end

        if heroData then
            atkSide = heroData:GetTeamType()
        end
        if not isIns then
            table.insert(skillDataList,{skillData = skillData,time = time,skillTime = skillTime,actionData = actionData,aId = aId})
        end

        if IsLog then
            logMgr:LogNormal(string.format("%s|%s使用技能名=%s|refId=%s,表现refid=%s",tostring(aId),tostring(heroData and heroData:GetName() or nil),
                    tostring(skillData and skillData:GetSkillName() or nil),tostring(skillRefId),tostring(expressionRefId)))
        end
    end

    if self._skipBattle then return end --是否跳过战斗


    self._waitTime = 0
    self:StepNextAction(true) ---结束技能等待
    self:StepNext(false)

    ---静默播放的战斗，直接计时
    if self._isPlayingSilently then
        local battleSpeed = 1
        local curTimeScale = MgrCenter.GameMgr:GetShouldTimeScale()
        ---界面加速周，后台战报播放过快的问题，因此放大播放时间
        local speed = battleSpeed / curTimeScale
        if speed < 1 then
            speed = 1
        end
        local backSkillTime = skillPlayTime / speed
        self._waitTime = backSkillTime + time
        if IsLog then
            logMgr:LogNormal("后台战斗英雄释放技能的表现时间：" .. tostring(backSkillTime))
        end
        return
    end

    local isOfflineRound = self:IsOfflineRound()

    self._waitTime = skillTime + time - 0.0001 --防止延迟一帧

    if isOfflineRound then
        self._waitTime = 0 -- 离线战斗回来要追平至离线回合
    end

    if self._agent then
        if recordPlayHeroId then
            self._agent:S2C_UpdateHeroPlay(recordPlayHeroId)
        end
        if updateBuffCount > 0 then
            self._agent:S2C_UpdateBuffData()
        end
        if updateTreasureCdCount > 0 then
            self._agent:S2C_UpdateTreasureCD()
        end
        self._agent:S2C_OnPlayActionList(atkSide, isOfflineRound, skillDataList, self._curRoundIndex, self._curBoutIdx, self._curActionIndex)
    end

end

