function LBattleLogicMgr:GetCurSpeedDataList()
    local roundData = self._curRoundData
    if not roundData or roundData.round < 1 then
        local roundDataList = self._reportData:GetRoundDataList()
        roundData = roundDataList[2]
        if not roundData then
            return {}
        end
    end

    local speedList = roundData:GetSpeedList()
    if not speedList then
        return {}
    end
    local speedDataList = self:FormatSpeedDataList(speedList)
    return speedDataList
end

---@param roundData LFightRoundData
function LBattleLogicMgr:GetAllBattleDataList(roundData)
    if not roundData then return {} end

    ---@type LFightBoutData[]
    local boutDataList = roundData:GetBoutDataList()
    if not boutDataList or #boutDataList < 1 then return {} end

    local speedIdsMap = {}
    local speedList = roundData:GetSpeedList()
    for i,v in ipairs(speedList) do
        speedIdsMap[v.id] = v.speed
    end
    local sort = 1
    local list = {}
    local beforeId
    for i,v in ipairs(boutDataList) do
        local insIdMap = {}
        ---@type LFightBoutActionData[]
        local actionDataList = v:GetActionDataList()
        ---@param val LFightBoutActionData[]
        for idx,val in ipairs(actionDataList) do
            for _i,_v in ipairs(val) do
                if _v:CheckIsAttack() then
                    local actAId = _v:GetAttackId()
                    if not insIdMap[actAId] or not self._playedHeros[actAId] then
                        if beforeId and beforeId == actAId then
                        else
                            local heroData = self:GetLogicUnit(actAId)
                            if heroData and heroData:IsHeroType() then
                                insIdMap[actAId] = true
                                beforeId = actAId
                                local itemData = {
                                    id = actAId,
                                    refId = heroData:GetRefId(),
                                    isMon = heroData:IsMonster(),
                                    star = heroData:GetStar(),
                                    skin = heroData:GetSkinId(),
                                    form = heroData:GetForm(),
                                    isRight = heroData:GetTeamType() == BattleTeamSide.teamB,
                                    isDead = heroData:IsDead(),
                                    speed = speedIdsMap[actAId] or -1,
                                    index = heroData:GetIndex(),
                                    sort = sort,
                                }
                                local quality = heroData:GetQuality()
                                if quality and quality > 0 then
                                    itemData.quality = quality
                                end
                                table.insert(list,itemData)
                                sort = sort + 1
                            end
                        end
                    end
                end
            end
        end
    end

    --table.sort(list,function (a,b)
    --	if a.speed ~= b.speed then
    --		return a.speed > b.speed
    --	end
    --
    --	if a.index ~= b.index then
    --		return a.index < b.index
    --	end
    --
    --	local aPrio = a.isRight and 2 or 1
    --	local bPrio = b.isRight and 2 or 1
    --	return aPrio < bPrio
    --end)

    return list
end

---@param speedList LBattleHeroSpeedData[]
function LBattleLogicMgr:FormatSpeedDataList(speedList)
    local dataList = {}
    for k,v in ipairs(speedList) do
        local id = v.id
        if not self._playedHeros[id] then
            local heroData = self:GetLogicUnit(id)
            ---@class VV_Battle_BattleHeroSpeedData
            local itemdata =
            {
                id = id,
                refId = heroData:GetRefId(),
                isMon = heroData:IsMonster(),
                star = heroData:GetStar(),
                skin = heroData:GetSkinId(),
                form = heroData:GetForm(),
                isRight = heroData:GetTeamType() == BattleTeamSide.teamB,
                isDead = heroData:IsDead(),
                speed = v.speed,
                index = heroData:GetIndex(),
            }
            local quality = heroData:GetQuality()
            if quality and quality>0 then
                itemdata.quality = quality
            end

            table.insert(dataList,itemdata)
        end
    end

    table.sort(dataList,function (a,b)
        if a.speed ~=  b.speed then
            return a.speed>b.speed
        end

        if a.index ~= b.index then
            return a.index<b.index
        end

        local aPrio = a.isRight and 2 or 1
        local bPrio = b.isRight and 2 or 1
        return aPrio<bPrio
    end)

    return dataList
end

function LBattleLogicMgr:IsHeroPlayed(id)
