end

---@region 新数据修改更新

---获取伤害次数
---@param actionData LFightBoutActionData
function LBattleLogicMgr:GetHurtCountFromActionData(actionData)
    local hurtCount = 0
    if not actionData then return hurtCount end
    local aId = actionData.aId
    --local playerHero = self:GetHeroData(aId)
    local effectArrays = actionData.effectArrays

    for k,effectArrayData in ipairs(effectArrays) do

        for m,effectListData in ipairs(effectArrayData.effectListArray) do

            local eid = effectListData.eId
            local baseEffectList = effectListData.baseEffectList

            for _x, baseEffect in ipairs(baseEffectList) do
                local effectType = baseEffect.type
                local tarData = self:GetLogicUnit(baseEffect.eId)
                local actionID = tonumber(baseEffect.aId)
                if not tarData or actionID < 0 then
                    break
                end

                --local atkData = self:GetHeroData(effect.aId) or playerHero
                if effectType == LFightConst.ACTIONEFFECTENUM_HURT and baseEffect.hitType == 1 then --伤害
                    if baseEffect.aId == aId and baseEffect.eId == eid then
                        hurtCount = hurtCount + 1
                    end
                end
            end
        end
    end

    return hurtCount
end

---数据模型更新
---@param actionData LFightBoutActionData
function LBattleLogicMgr:UpdateHeroDataFromActionData(actionData)
    if not actionData then return end
    local aId = actionData.aId
    local playerHero = self:GetLogicUnit(aId)

    local effectArrayList = actionData.effectArrays

    ---溅射不传入buffMap记录了
    --local buffMap = self:RecordTakeJSBuff(effectArrayList,playerHero)

    for k,effectArrayData in ipairs(effectArrayList) do
        for m,effectListData in ipairs(effectArrayData.effectListArray) do
            for _x,baseEffect in ipairs(effectListData.baseEffectList) do
                self:ExecuteLogicBaseEffect(baseEffect,playerHero)
                if baseEffect.spurtingList then
                    for k,v in ipairs(baseEffect.spurtingList) do
                        --self:ExecuteLogicBaseEffect(v,playerHero,buffMap[v.eId])
                        ---溅射不传入buffMap记录了
                        self:ExecuteLogicBaseEffect(v,playerHero)
                    end
                end
            end
        end
    end
end

---@param playerHero LBattleLogicUnit
---@param effectArrayList LBattleEffectArrayData[]
function LBattleLogicMgr:RecordTakeJSBuff(effectArrayList,playerHero)
    if not playerHero then return {} end
    if not effectArrayList or #effectArrayList < 1 then return {} end

    local buffEffects = {}
    local playerHeroId = playerHero:GetId()

    local buffResultList = {}
    local buffMap = {}
    --- 判断技能是否包含溅射
    for k,effectArrayData in ipairs(effectArrayList) do
        for m,effectListData in ipairs(effectArrayData.effectListArray) do
            for _x,baseEffect in ipairs(effectListData.baseEffectList) do
                if baseEffect.aId == playerHeroId then
                    if baseEffect.type == LFightConst.ACTIONEFFECTENUM_BUFF then
                        local buffEffectData = baseEffect.buffEffect
                        if buffEffectData.etype == LFightConst.BUFF_TYPE_ADD then
                            local buffId = buffEffectData.buffId
                            if buffId and buffId > 0 then
                                local hasJS,buffEffectRef = self._dataMgr:CheckBuffHasJianShe(buffId)
                                if hasJS then
                                    table.insert(buffEffects,buffEffectRef)
                                end
                            end
                        end
                    elseif baseEffect.type == LFightConst.ACTIONEFFECTENUM_HURT then
                        local hurtEffectData = baseEffect.hurtEffect
                        if hurtEffectData.spurtingList and #hurtEffectData.spurtingList > 0 then
                            for idx,val in ipairs(hurtEffectData.spurtingList) do
                                table.insert(buffResultList, {
                                    eId = val.eId,
                                    --- 目标id
                                    targetId = baseEffect.eId,
                                    targetObj = self:GetLogicUnit(baseEffect.eId),
                                    isUse = false,
                                    buffEffectRef = nil,
                                })
                            end
                        end
                    end

                end
            end
        end
    end
    if #buffEffects < 1 then return buffMap end
    if #buffResultList < 1 then return buffMap end

    local buffAllNum = #buffEffects
    local buffNum = 0

    for k,val in ipairs(buffResultList) do
        buffNum = buffNum + 1
        local buffEffectRef = buffEffects[buffNum]
        if not buffEffectRef then
            buffEffectRef = buffEffects[buffAllNum]
            print("超出下标")
        end
        val.buffEffectRef = buffEffectRef
        buffMap[val.eId] = val
        val.eid = nil
    end
    return buffMap
end

---@param baseEffect LBattleBaseEffectData
function LBattleLogicMgr:ExecuteLogicBaseEffect(baseEffect, playerHero, takeEffData)
    local effectType = baseEffect.type
    local aId = baseEffect.aId
    local eId = baseEffect.eId
    local targetType = baseEffect.targetType
    local hitType = baseEffect.hitType

    local tarData = self:GetLogicUnit(eId)
    if not tarData then return end

    local logMgr = self:GetLogMgr()

    local atkData = self:GetLogicUnit(aId) or playerHero

    if effectType == LFightConst.ACTIONEFFECTENUM_HURT then --伤害
        local hurtEffectData = baseEffect.hurtEffect
        local hurt = hurtEffectData.hurt

        local side = self:GetOppositeSide(tarData:GetTeamType())
        self:AddHurtCnt(side,hurt)
        --isHurtChange = true
        local oldHp = tarData:GetHp()

        if hurtEffectData.ht == LFightConst.HURT_TYPE_PARRYING then
            tarData:UpdateBlockData()
        else
            local hp = hurtEffectData.afterHp
            tarData:RefreshCurHp(hp)
        end

        if hurtEffectData.dead then
            local canRelive = self:CheckCanRelive(eId)
            tarData:SetDead(true,canRelive)
        end
        tarData:UpdateBearDamageCount(hurt)
        if atkData then
            atkData:UpdateDamageCount(hurt)
        end

        --if takeEffData and takeEffData.buffEffectRef then
        --	---@type LFightObject
        --	local tarObj = self:GetUnitView(effect.eId)
        --	---@type LFightObject
        --	local takeObj = self:GetUnitView(takeEffData.targetId)
        --	if tarObj and takeObj then
        --		-- 播放溅射
        --		local buffEffectRef = takeEffData.buffEffectRef
        --		if buffEffectRef and not string.isempty(buffEffectRef.showEffect) then
        --			local effectCtrl = self:GetEffectCtrl()
        --			if side == BattleTeamSide.teamA then
        --			elseif side == BattleTeamSide.teamB then
        --			end
        --			local playTime = 1
        --			local dissipateTime = 1
        --			local tarDisplayTrans = tarObj:GetDisplayObj():GetDpTrans()
        --			local tarPos = tarObj:GetDisplayObj():GetPos()
        --			local dir = takeObj:GetDirection()
        --			---@type LFightEffect
        --			local _effect = effectCtrl:MakeEffectObject(tarDisplayTrans,buffEffectRef.showEffect,tarPos,dir,1.22,playTime,dissipateTime)
        --			_effect:SetBullet(true, takeObj:GetDisplayObj():GetPos(), playTime, 0,1)
        --			_effect:SetEffectPara({
        --				isUpperLayer= takeObj:IsUpperLayer(),
        --				scale = 1,
        --			})
        --			effectCtrl:AddEffect(_effect)
        --		end
        --	end
        --end


        if logMgr:IsLogOpen() then
            logMgr:LogHpChange(tarData:GetId(),tarData:GetMaxHp(),tarData:GetHp(),oldHp,-hurt)
        end

    elseif effectType == LFightConst.ACTIONEFFECTENUM_BUFF then --buff
        local buffEffectData = baseEffect.buffEffect
        local buff = {}
        buff.buffUniqueId = buffEffectData.buffUniqueId
        buff.buffId = buffEffectData.buffId
        buff.round = buffEffectData.round
        buff.startRound = self._roundCount == 0 and 1 or self._roundCount
        buff.currentRound = buffEffectData.round
        tarData:DoBuffUpdate(buff, buffEffectData.etype)

        if buffEffectData.etype == LFightConst.BUFF_TYPE_REMOVE then
            self._unitMgr:InsertWaitRemove(buffEffectData.buffUniqueId)
        end

    elseif effectType == LFightConst.ACTIONEFFECTENUM_TREATS then --治疗
        local treadEffectData = baseEffect.treatEffect
        local treat = treadEffectData.treat
        local oldHp = tarData:GetHp()
        local hp = treadEffectData.afterHp
        tarData:RefreshCurHp(hp)

        if treadEffectData.isRelive then
            tarData:SetDead(false)
        end

        if logMgr:IsLogOpen() then
            logMgr:LogHpChange(tarData:GetId(),tarData:GetMaxHp(),tarData:GetHp(),oldHp,treat)
        end

        if atkData then
            atkData:UpdateTreatmentCount(treat)
        end
    elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELD then --护盾
        local shieldEffectData = baseEffect.shieldEffect
        local shield = {}
        shield.buffUniqueId = shieldEffectData.buffUniqueId
        shield.shieldUniqueId = shieldEffectData.shieldUniqueId
        shield.maxHP = shieldEffectData.hp
        shield.curHP = shieldEffectData.hp
        tarData:AddShieldData(shield)

    elseif effectType == LFightConst.ACTIONEFFECTENUM_PSHIELD then --格挡盾
        local pShieldEffectData = baseEffect.pShieldEffect
        local block = {}
        block.buffUniqueId = pShieldEffectData.buffUniqueId
        block.blockUniqueId = pShieldEffectData.blockUniqueId
        block.maxCount = pShieldEffectData.count
        block.curCount = pShieldEffectData.count
        tarData:AddBlockData(block)

    elseif effectType == LFightConst.ACTIONEFFECTENUM_ANGER then --怒气
        local angerEffectData = baseEffect.angerEffect
        local anger = {}
        anger.buffUniqueId = angerEffectData.buffUniqueId
        anger.angerValue = angerEffectData.angerValue
        tarData:AddAngerData(anger)

    elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELDHURT then --护盾抵挡伤害
        local shieldHurtEffectData = baseEffect.shieldHurtEffect
        local shield = {}
        shield.shieldUniqueId = shieldHurtEffectData.shieldUniqueId
        shield.hurt = - shieldHurtEffectData.hurt

        tarData:UpdateBearDamageCount(shield.hurt)
        if atkData then
            atkData:UpdateDamageCount(shield.hurt)
        end
        tarData:UpdateShieldData(shield)
    elseif effectType == LFightConst.ACTIONEFFECTENUM_POSITION then

        --[[		local side = tarData:GetTeamType()
                local oldIndex = effect.oldIndex
                local heroData = self:GetHeroDataByIndex(side,oldIndex)
                if heroData then
                    heroData:UpdateIndex(effect)
                end
                local newIndex = effect.newIndex
                heroData = self:GetHeroDataByIndex(side,newIndex)
                if heroData then
                    heroData:UpdateIndex(effect)
                end]]

        local positionEffectData = baseEffect.positionEffect
        local heroData = self:GetLogicUnit(eId)
        if heroData then
            heroData:UpdateIndex1(positionEffectData)
        end

        --self:UpdateHeroDataMap()
    elseif effectType == LFightConst.ACTIONEFFECTENUM_SUMMON then
        self._unitMgr:AddSummon(baseEffect)
    elseif effectType == LFightConst.ACTIONEFFECTENUM_ROUND then
        tarData:UpdateRoundData(baseEffect)
    end

    self:UpdateBloodPercentBack()
end

function LBattleLogicMgr:UpdateBloodPercentBack()
    if not self._isPlayingSilently then
        return
    end

    local mapFormationData = self:GetMapFormationData()
    local totalHpA = 0
    local totalHpB = 0
    local curHpA = 0
    local curHpB = 0
    for k,v in pairs(mapFormationData) do
        local objType = v:GetBattleObjType()
        if objType == LFightConst.OBJ_NORMAL then
            local side = v:GetTeamType()
            if side == BattleTeamSide.teamA then
                totalHpA = totalHpA + v:GetMaxHp()
                curHpA = curHpA + v:GetHp()
            else
                totalHpB = totalHpB + v:GetMaxHp()
                curHpB = curHpB + v:GetHp()
            end
        end
    end

    local percentA = 1
    if totalHpA >0 then
        percentA = curHpA/totalHpA
    end

    local percentB = 1
    if totalHpB >0 then
        percentB = curHpB/totalHpB
    end

    self:RefreshBloodPercent(true,percentA)
    self:RefreshBloodPercent(false,percentB)

end

function LBattleLogicMgr:AddHurtCnt(side,hurt)

    local curHurt = self._teamHurtCnt[side] or 0
    curHurt = curHurt + hurt
    self._teamHurtCnt[side] = curHurt


end

