function LBattleLogicMgr:UpdateHeroDataBuffData()
    local round = self._round
    local nowRound = self._roundCount
    local checkBuff = false
    if(round ~= nowRound) then
        self._round = nowRound
        checkBuff = true
    end
    if checkBuff then
        local mapFormationData = self._unitMgr:GetMapFormationData()
        for i, heroData in pairs(mapFormationData) do
            heroData:OnUpdateBuffRound(nowRound)
        end
    end
    return checkBuff
end

