function LBattleLogicMgr:CalcOfflineRoundCount()
    if self._offlineTime<= 0 then
        return
    end

    local ref = GameTable.BattleGameRef[self._battleType]
    if not ref then
        return
    end

    local roundCount = self._totalRoundIndex

    local timeout = ref.timeout
    local offlineRound = math.floor(self._offlineTime/timeout*roundCount)
    offlineRound = offlineRound >= roundCount and roundCount -1 or offlineRound --防止死循环
    self._offlineTime = 0

    self._offlineRound = offlineRound
end

