---@region 销毁
function LBattleLogicMgr:IsDisposed()
    return self._isDisposed
end

function LBattleLogicMgr:Dispose()
    if self._isDisposed then return end
    if LOG_INFO_ENABLED then
        print("LBattleLogicMgr:Dispose()  reportId : "..tostring(self._reportId))
    end

    if self._agent then
        self._agent:Dispose()
    end

    if self._fsm then
        self._fsm:Dispose()
    end

    if self._unitMgr then
        self._unitMgr:Dispose()
    end


    if self._logMgr then
        self._logMgr:Dispose()
    end

    local combatType = self._battleType

    table.dispose(self)

    self._battleType = combatType
    self._isDisposed = true
end
---@endregion 销毁


return LBattleLogicMgr